svg.script:
function show_a7702cee(evt, text) {
	var pos = (evt.target.getAttribute("y") < 819) ? "bottom" : "top";
	var note = document.getElementById(pos + "_note_a7702cee");
	note.textContent = text;
	note.setAttributeNS(null, "visibility", "visible");
	document.getElementById(pos + "_overlay_a7702cee").setAttributeNS(null, "visibility", "visible");
}
function hide_a7702cee(evt) {
	document.getElementById("top_note_a7702cee").setAttributeNS(null, "visibility", "hidden");
	document.getElementById("top_overlay_a7702cee").setAttributeNS(null, "visibility", "hidden");
	document.getElementById("bottom_note_a7702cee").setAttributeNS(null, "visibility", "hidden");
	document.getElementById("bottom_overlay_a7702cee").setAttributeNS(null, "visibility", "hidden");
}
